from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    if not search_results or not filter_specs:
        return search_results

    logic_normalized = filter_logic.strip().upper()
    if logic_normalized not in {"AND", "OR"}:
        raise ValueError(f"Unsupported filter_logic '{filter_logic}'. Use 'AND' or 'OR'.")

    # Convert SearchResult objects to dictionaries for filtering
    result_dicts: List[Dict[str, Any]] = []
    for res in search_results:
        # Prefer a standard conversion method if available
        if hasattr(res, "to_dict") and callable(getattr(res, "to_dict")):
            data = res.to_dict()
        else:
            # Fallback: use __dict__ while skipping private/internal attributes
            data = {
                k: v
                for k, v in getattr(res, "__dict__", {}).items()
                if not k.startswith("_")
            }

        # Ensure metadata is present under a predictable key if SearchResult exposes it
        if hasattr(res, "metadata"):
            # Avoid overwriting if already present in data
            if "metadata" not in data:
                data["metadata"] = getattr(res, "metadata")

        result_dicts.append(data)

    # Initialize the MetadataFilterEngine with specified logic
    engine = MetadataFilterEngine(logic=logic_normalized)

    # Build conditions list from filter_specs
    # Expected internal format for MetadataFilterEngine:
    #   [{"field": field_name, "op": operator, "value": value}, ...]
    conditions = []
    for field, ops in filter_specs.items():
        if not isinstance(ops, dict):
            raise ValueError(
                f"Invalid filter specification for field '{field}': expected dict of operators."
            )
        for op, value in ops.items():
            conditions.append({"field": field, "op": op, "value": value})

    # Apply filters to the list of dictionaries
    filtered_dicts = engine.filter(result_dicts, conditions)

    # Map filtered dictionaries back to original SearchResult objects in original order
    # We match by object identity where possible, falling back to dict equality if needed.
    filtered_results: List[SearchResult] = []

    # Build helper structures for matching
    # First try a direct index match when dict originated from to_dict()
    for res, res_dict in zip(search_results, result_dicts):
        if res_dict in filtered_dicts:
            filtered_results.append(res)

    return filtered_results
