    # Initialize a PassageManager for the given index
    # (Assumes PassageManager can be initialized with the index path)
    manager = PassageManager(str(index_path_obj))

    # Attempt to locate the passages data file using PassageManager helpers,
    # falling back to a conventional location if necessary.
    passages_file: Path

    # Prefer a helper/attribute if PassageManager exposes it
    if hasattr(manager, "passages_path"):
        passages_file = Path(manager.passages_path)
    elif hasattr(manager, "get_passages_path"):
        passages_file = Path(manager.get_passages_path())
    else:
        # Fallback: assume a conventional filename in the index directory
        # e.g., "passages.jsonl" or "passages.json"
        # Try jsonl first, then json.
        jsonl_candidate = index_path_obj / "passages.jsonl"
        json_candidate = index_path_obj / "passages.json"
        if jsonl_candidate.is_file():
            passages_file = jsonl_candidate
        else:
            passages_file = json_candidate

    # If the passages file does not exist, return empty list as required
    if not passages_file.is_file():
        return []

    matching_passages: List[Dict[str, Any]] = []

    # Determine format based on extension: jsonl (one JSON per line)
    # vs single JSON (list of passages or dict with passages)
    suffix = passages_file.suffix.lower()

    try:
        if suffix == ".jsonl":
            # Stream through lines to avoid loading everything at once
            with passages_file.open("r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        passage = json.loads(line)
                    except json.JSONDecodeError:
                        continue  # skip malformed lines
                    if _matches_metadata_criteria(passage, metadata_criteria):
                        matching_passages.append(passage)
        else:
            # Assume standard JSON file
            with passages_file.open("r", encoding="utf-8") as f:
                data = json.load(f)

            # Data could be a list of passages or a dict containing them
            if isinstance(data, list):
                passages_iter = data
            elif isinstance(data, dict):
                # Try common keys
                if "passages" in data and isinstance(data["passages"], list):
                    passages_iter = data["passages"]
                else:
                    # If structure is unknown, treat entire dict as a single passage
                    passages_iter = [data]
            else:
                passages_iter = []

            for passage in passages_iter:
                if not isinstance(passage, dict):
                    continue
                if _matches_metadata_criteria(passage, metadata_criteria):
                    matching_passages.append(passage)
    except (OSError, json.JSONDecodeError):
        # On any read/parse issues, return empty list per requirements
        return []

    return matching_passages


def _matches_metadata_criteria(
    passage: Dict[str, Any],
    criteria: Dict[str, Any]
) -> bool:
    """Return True if passage matches all metadata criteria (AND logic)."""
    if not criteria:
        # If no criteria, treat as match-all
        return True

    # Metadata may be stored under 'metadata' or directly at top level.
    metadata = passage.get("metadata", {})
    if not isinstance(metadata, dict):
        metadata = {}

    for key, expected_value in criteria.items():
        # Prefer metadata field; fall back to top-level if not present
        if key in metadata:
            value = metadata.get(key)
        else:
            value = passage.get(key)

        if value != expected_value:
            return False

    return True
